(()=>{const init=()=>{const modals=document.querySelectorAll('.search-modal[role="dialog"]');if(!modals.length)return;document.addEventListener('keydown',(e)=>{if(e.key!=='Escape')return;modals.forEach((modal)=>{if(modal.classList.contains('has-display-none'))return;const close=document.querySelector('.search-close button,.search-close a');if(close)close.click();});});modals.forEach((modal)=>{modal.addEventListener('keydown',(e)=>{if(e.key!=='Tab')return;const focusable=modal.querySelectorAll('input,button,a[href],textarea,select,[tabindex]:not([tabindex="-1"])');if(!focusable.length)return;const first=focusable[0];const last=focusable[focusable.length-1];if(e.shiftKey){if(document.activeElement===first){e.preventDefault();last.focus();}}else{if(document.activeElement===last){e.preventDefault();first.focus();}}});});};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}})();
